  7	import {
  8	  K8sModel,
  9	  K8sResourceCommon,
 10	  K8sResourceKind,
 11	  ResourceLink,
 12	  Timestamp,
 13	  useAccessReview,
 14	  useAnnotationsModal,
 15	  useLabelsModal,
 16	} from '@openshift-console/dynamic-plugin-sdk';
 17	import { DetailsItem } from './details-item';
 18	import { LabelList } from './label-list';
 19	import { referenceFor } from '../utils/k8s-utils';
 20	import { Selector } from './selector';
 21	import { OwnerReferences } from './owner-references';
 22	
 23	export const pluralize = (
 24	  i: number,
 25	  singular: string,
 26	  plural = `${singular}s`,
 27	  includeCount = true,
 28	) => {
 29	  const pluralized = `${i === 1 ? singular : plural}`;
 30	  return includeCount ? `${i || 0} ${pluralized}` : pluralized;
 31	};
 32	
 33	export const detailsPage = <T extends Record<string, any>>(
 34	  Component: React.ComponentType<T>,
 35	) =>
 36	  function DetailsPage(props: T) {
 37	    return <Component {...props} />;
 38	  };
 39	
 40	export const ResourceSummary: React.FC<ResourceSummaryProps> = ({
 41	  children,
 42	  resource,
 43	  customPathName,
 44	  showPodSelector = false,
 45	  showNodeSelector = false,
 46	  showAnnotations = true,
 47	  showLabelEditor = true,
 48	  canUpdateResource = true,
 49	  podSelector = 'spec.selector',
 50	  nodeSelector = 'spec.template.spec.nodeSelector',
 51	  model,
 52	}) => {
 53	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 54	  const { metadata } = resource;
 55	  const reference = referenceFor(resource);
 56	  const annotationsModalLauncher = useAnnotationsModal(resource);
 57	  const labelsModalLauncher = useLabelsModal(resource);
 58	  const canUpdateAccess = useAccessReview({
 59	    group: model.apiGroup,
 60	    resource: model.plural,
 61	    verb: 'patch',
 62	    name: metadata.name,
 63	    namespace: metadata.namespace,
 64	  });
 65	  const canUpdate = canUpdateAccess && canUpdateResource;
 66	
 67	  return (
 68	    <DescriptionList data-test-id="resource-summary">
 69	      <DetailsItem
 70	        label={t('Name')}
 71	        obj={resource}
 72	        path={customPathName || 'metadata.name'}
 73	      />
 74	      {metadata.namespace && (
 75	        <DetailsItem
 76	          label={t('Namespace')}
 77	          obj={resource}
 78	          path="metadata.namespace"
 79	        >
 80	          <ResourceLink
 81	            kind="Namespace"
 82	            name={metadata.namespace}
 83	            title={metadata.uid}
 84	            namespace={null}
 85	          />
 86	        </DetailsItem>
 87	      )}
 88	      <DetailsItem
 89	        label={t('Labels')}
 90	        obj={resource}
 91	        path="metadata.labels"
 92	        valueClassName="details-item__value--labels"
 93	        onEdit={labelsModalLauncher}
 94	        canEdit={showLabelEditor && canUpdate}
 95	        editAsGroup
 96	      >
 97	        <LabelList kind={reference} labels={metadata.labels} />
 98	      </DetailsItem>
 99	      {showPodSelector && (
100	        <DetailsItem
101	          label={t('Pod selector')}
102	          obj={resource}
103	          path={podSelector}
104	        >
105	          <Selector
106	            selector={_.get(resource, podSelector)}
107	            namespace={_.get(resource, 'metadata.namespace')}
108	          />
109	        </DetailsItem>
110	      )}
111	      {showNodeSelector && (
112	        <DetailsItem
113	          label={t('Node selector')}
114	          obj={resource}
115	          path={nodeSelector}
116	        >
117	          <Selector kind={t('Node')} selector={_.get(resource, nodeSelector)} />
118	        </DetailsItem>
119	      )}
120	      {showAnnotations && (
121	        <DetailsItem
122	          label={t('Annotations')}
123	          obj={resource}
124	          path="metadata.annotations"
125	        >
126	          {canUpdate ? (
127	            <Button
128	              data-test="edit-annotations"
129	              type="button"
130	              isInline
131	              onClick={annotationsModalLauncher}
132	              variant="link"
133	            >
134	              {t('{{count}} annotation', {
135	                count: _.size(metadata.annotations),
136	              })}
137	              <PencilAltIcon className="co-icon-space-l pf-v6-c-button-icon--plain" />
138	            </Button>
139	          ) : (
140	            t('{{count}} annotation', {
141	              count: _.size(metadata.annotations),
142	            })
143	          )}
144	        </DetailsItem>
145	      )}
146	      {children}
147	      <DetailsItem
148	        label={t('Created at')}
149	        obj={resource}
150	        path="metadata.creationTimestamp"
151	      >
152	        <Timestamp timestamp={metadata.creationTimestamp} />
153	      </DetailsItem>
154	      <DetailsItem
155	        label={t('Owner')}
156	        obj={resource}
157	        path="metadata.ownerReferences"
158	      >
159	        <OwnerReferences resource={resource} />
160	      </DetailsItem>
161	    </DescriptionList>
162	  );
163	};
164	
165	export type ResourceSummaryProps = {
166	  resource: K8sResourceKind;
167	  showPodSelector?: boolean;
168	  showNodeSelector?: boolean;
169	  showAnnotations?: boolean;
170	  showTolerations?: boolean;
171	  showLabelEditor?: boolean;
172	  canUpdateResource?: boolean;
173	  podSelector?: string;
174	  nodeSelector?: string;
175	  children?: React.ReactNode;
176	  customPathName?: string;
177	  model?: K8sModel;
178	};
179	
180	export type ResourcePodCountProps = {
181	  resource: K8sResourceKind;
182	};
183	
184	export type RuntimeClassProps = {
185	  obj: K8sResourceCommon;
186	  path?: string;
187	};
188	
189	ResourceSummary.displayName = 'ResourceSummary';

